INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  4,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-РАЗБОР С LEXI: СЕКРЕТ ГЛАГОЛА TO BE\n\nПривет! Сегодня мы разбираем тему, без которой невозможно построить даже самое простое предложение на английском. Это глагол TO BE.\n\nИменно он постоянно путает новичков, потому что в русском языке мы его обычно мысленно упускаем, а вот в английском он - основа всего.\n\nLexi на пальцах объяснит, почему англичане никогда не говорят \"Я счастливый\" напрямую, и как раз и навсегда запомнить формы am, is и are.","video_url":"https://vk.com/video-230370533_456239027","vk_attachment":"video-230370533_456239027","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  4,
  2,
  'theory',
  '{"text":"✨ УРОК 4. БАЗОВАЯ ГРАММАТИКА: ГЛАГОЛ TO BE\n\nВ русском языке мы легко говорим: \"Я счастлива\", \"Она студентка\", \"Они друзья\". Мы просто соединяем слова друг с другом. \n\nВ английском так делать нельзя! Английское предложение строгое, оно не может существовать без глагола-действия. \n\nЕсли реального действия (бежать, делать, программировать) в нашей фразе нет, то на место глагола приходит TO BE (быть, являться, существовать). Мы как бы говорим: \"Я ЕСТЬ счастливый\".\n\nУ этого глагола есть три формы, которые зависят от того, КТО совершает действие:\n\n👑 ФОРМА AM (живет только с местоимением Я)\n• I am... [ай эм]\nПример: I am happy [ай эм хэ́ппи] - Я счастлив (дословно: Я есть счастливый).\n\n👑 ФОРМА IS (для единственного числа: он, она, оно)\n• He is... / She is... / It is... [хи из / ши из / ит из]\nПример: She is a student [ши из а стью́дент] - Она студентка.\n\n👑 ФОРМА ARE (для множественного числа: мы, вы, они)\n• We are... / You are... / They are... [уи ар / ю ар / зэй ар]\nПример: They are friends [зэй ар фрэндз] - Они друзья.","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  4,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: РАЗГОВОР В ОФИСЕ\n\nДавайте посмотрим, как новые сотрудники общаются в ИТ-компании, используя формы глагола to be:\n\nTom: Hi! I am Tom. I am a project manager.\nAnna: Hello Tom! My name is Anna. I am happy to meet you. \nTom: Nice to meet you too! Who is that girl?\nAnna: She is Maria. She is a student and our new intern. \nTom: Awesome! And who are those guys over there?\nAnna: They are developers. They are friends.\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nТом: Привет! Я Том. Я проджект-менеджер.\nАнна: Привет, Том! Меня зовут Анна. Я рада знакомству.\nТом: Мне тоже приятно! А кто та девушка?\nАнна: Это Мария. Она студентка и наш новый стажер.\nТом: Круто! А кто вон те ребята?\nАнна: Они разработчики. Они друзья.\n\n💡 РАЗГОВОРНЫЙ ЛАЙФХАК:\nВ реальной жизни иностранцы почти никогда не произносят эти слова полностью. Они их сокращают, сливая с местоимениями:\n• I am - I''m [айм]\n• She is - She''s [шиз]\n• They are - They''re [зэ́я]\n\n🔥 Ваше мини-задание: Произнеси вслух три главные фразы из этого урока, используя короткую форму: \"I''m happy\", \"She''s a student\", \"They''re friends\". Почувствуй, как это ускоряет твою речь!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


