VALUES (
  5,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-ПРАКТИКА С LEXI: ЖИВОЙ РАЗГОВОР\n\nПривет! Вы уже знаете отдельные фразы, умеете называть имя, свою страну и использовать глагол to be. Настало время объединить все это в один классный, плавный диалог.\n\nСегодня мы научимся не просто отвечать на вопросы, а вести полноценную легкую беседу при знакомстве с иностранцем в чате или на созвоне.\n\nLexi записала короткое видео, котороеразберет, как звучит живой диалог на слух, покажет правильную интонацию вопросов и подскажет, как отвечать на автомате, не задумываясь над каждым словом.","video_url":"https://vk.com/video-230370533_456239028","vk_attachment":"video-230370533_456239028","button_text":"К теории ➡️"}'
)
