  1,
  'theory',
  '{"text":"🎬 ВИДЕО-УРОК ОТ LEXI: КТО ЕСТЬ КТО В АНГЛИЙСКОМ\n\nПривет! На связи Lexi. Сегодня мы разберем личные местоимения - слова, которые заменяют имена людей и названия предметов: я, ты, он, она, они.\n\nБез них невозможно рассказать о себе, обсудить команду или описать проект. Но в английском языке у этих простых слов есть парочка скрытых ловушек, на которых часто спотыкаются новички.\n\nВключайте короткое видео! Мы разберем правильное произношение и главные секреты местоимений, которые облегчат Вам понимание всей дальнейшей грамматики.","video_url":"https://vk.com/video-230370533_456239029","vk_attachment":"video-230370533_456239029","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  6,
  2,
  'theory',
  '{"text":"✨ УРОК 6. ЛИЧНЫЕ МЕСТОИМЕНИЯ\n\nВ английском языке всего 7 личных местоимений. Давай разберем их подробно.\n\nЕДИНСТВЕННОЕ ЧИСЛО:\n\n• I [ай] - Я\nЗапомни: это слово ВСЕГДА пишется с заглавной (большой) буквы, в любом месте предложения! Даже в самой середине.\n\n• You [ю] - Ты / Вы\nВ английском нет разделения на уважительное \"Вы\" и дружеское \"ты\". Для любого человека используется только \"You\".\n\n• He [хи] - Он (только для мужчин и мальчиков)\n• She [ши] - Она (только для женщин и девочек)\n\n• It [ит] - Оно / Это\nА вот это супер-важное слово! В английском языке ВСЕ неодушевленные предметы (телефон, машина, код, офис) и ВСЕ животные (кошка, собака, птица) - это \"It\". \nДля англичан стол - это не \"он\", а \"оно\". Кошка - это тоже \"оно\".\n\nМНОЖЕСТВЕННОЕ ЧИСЛО:\n\n• We [уи] - Мы\n• They [зэй] - Они (подходит и для людей, и для предметов/животных).","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  6,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: ОБСУЖДАЕМ КОМАНДУ\n\nДавайте посмотрим, как менеджер Сэм и разработчик Анна используют местоимения в рабочем разговоре:\n\nSam: Hi Anna! Look at this new laptop. It is very fast!\nAnna: Oh, hello Sam! Yes, it is great. \nSam: Where are Alex and Max? Are they in the office?\nAnna: No, they are at home today. We are a remote team now!\nSam: Good. And who is that woman? \nAnna: She is Marina. She is our new team lead. She is very smart!\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nСэм: Привет, Анна! Посмотри на этот новый ноутбук. Он очень быстрый! (в оригинале - It)\nАнна: О, привет, Сэм! Да, он отличный. (в оригинале - it)\nСэм: А где Алекс и Макс? Они в офисе? (they)\nАнна: Нет, они сегодня дома. Мы теперь удаленная команда! (they, we)\nСэм: Хорошо. А кто та женщина?\nАнна: Это Марина. Она наш новый тимлид. Она очень умная! (she)\n\n💡 ГРАММАТИЧЕСКИЙ ЛАЙФХАК:\nСлово \"You\" (Ты / Вы) в английском языке ГРАММАТИЧЕСКИ всегда считается множественным числом. Даже если ты обращаешься к одному единственному другу. \nИменно поэтому с \"You\" всегда используется форма глагола \"are\", а не \"is\". Запомни: \"You are\", но никогда не \"You is\"!\n\n🔥 Твое мини-задание: Посмотри вокруг себя и назови 3 предмета, используя местоимение \"It\". Например, укажи на телефон и скажи: \"It is a phone\".","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


