INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  7,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-УРОК ОТ LEXI: ЧЬЯ ЭТО ВЕЩЬ?\n\nПривет! На связи Lexi. В прошлом уроке мы разобрались с местоимениями (я, ты, он, она). Сегодня мы сделаем следующий логический шаг - научимся говорить, кому что принадлежит.\n\nМой ноутбук, твой код, ее чашка кофе, наш проект - все это притяжательные слова. В живой речи они используются на каждом шагу, ведь нам постоянно нужно обозначать право собственности на вещи.\n\nВключайте короткое видео! Я покажу Вам правильное произношение этих слов без жесткого акцента и разберу главную ошибку, которую делают 95% новичков при переводе слова \"свой\".","video_url":"https://vk.com/video-230370533_456239030","vk_attachment":"video-230370533_456239030","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  7,
  2,
  'theory',
  '{"text":"✨ УРОК 7. ПРИТЯЖАТЕЛЬНЫЕ СЛОВА\n\nВ русском языке у нас есть волшебное и ленивое слово \"свой\". Мы говорим: \"Я взял свою сумку\", \"Она взяла свою сумку\", \"Они взяли свою сумку\". \n\nВ английском языке слова \"свой\" НЕ СУЩЕСТВУЕТ! Вместо него англичане всегда используют конкретное притяжательное слово, привязанное к хозяину вещи.\n\nДАВАЙ ИХ ИЗУЧИМ:\n\n• My [май] - Мой / Моя / Мое\nСвязано с местоимением \"I\" (Я). \nПример: My phone - Мой телефон (дословно: я взял МОЙ телефон).\n\n• Your [юэ] - Твой / Ваш\nСвязано с местоимением \"You\" (Ты / Вы).\nПример: Your project - Твой проект.\n\n• His [хиз] - Его\nСвязано с местоимением \"He\" (Он, только про мужчин).\nПример: His laptop - Его ноутбук.\n\n• Her [хёр] - Ее\nСвязано с местоимением \"She\" (Она, только про женщин).\nПример: Her coffee - Ее кофе.\n\n• Our [áуэ] - Наш / Наша / Наше\nСвязано с местоимением \"We\" (Мы).\nПример: Our team - Наша команда.\n\n• Their [зэа] - Их\nСвязано с местоимением \"They\" (Они).\nПример: Their office - Их офис.","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  7,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: ПОИСК ВЕЩЕЙ В ОФИСЕ\n\nПосмотри, как маркетолог Макс и дизайнер София наводят порядок на рабочем столе перед митингом:\n\nMax: Sofia, look! Is this your smartphone?\nSofia: No, it is not my smartphone. My phone is black. This phone is blue.\nMax: Oh, I see. It is his phone. It is Alex''s phone.\nSofia: And look at that modern office over there. Is it our new room?\nMax: No, it is their room. They are developers. Our room is next door.\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nМакс: София, посмотри! Это твой смартфон?\nСофия: Нет, это не мой смартфон. Мой телефон черный. Этот телефон синий.\nМакс: О, я понял. Это его телефон. Это телефон Алекса.\nСофия: И посмотри на тот современный офис вон там. Это наш новый кабинет?\nМакс: Нет, это их кабинет. Они разработчики. Наш кабинет по соседству.\n\n💡 ГЛАВНЫЙ СУПЕР-ЛАЙФХАК:\nВ английском языке притяжательные слова - это сплошное удовольствие, потому что они НИКОГДА не меняются по родам и числам!\nСравни сам: в русском мы говорим: мой телефон, моя чашка, мои ключи (три разных окончания). В английском во всех случаях будет просто MY: my phone, my cup, my keys. Никаких окончаний учить не нужно!\n\n🔥 Твое мини-задание: Назови три любые вещи на своем столе, используя слово \"My\". Например: \"My laptop\", \"My coffee\". Почувствуй, как это просто!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


