INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  8,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-УРОК ОТ LEXI: МИР ВАШЕЙ СЕМЬИ\n\nПривет! На связи Lexi. Сегодня мы разберем одну из самых теплых, уютных и популярных тем в любом языке - тему семьи.\n\nМы научимся правильно называть своих самых близких людей: родителей, братьев и сестер. Это то, о чем Вас обязательно спросят при дружеской беседе в чате или за ужином с новыми знакомыми.\n\nВключайте короткое видео! Я помогу Вам разобраться с произношением коварного звука \"th\" в словах mother и father, чтобы Вы звучали естественно, красиво и без сильного славянского акцента.","video_url":"https://vk.com/video-230370533_456239031","vk_attachment":"video-230370533_456239031","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  8,
  2,
  'theory',
  '{"text":"✨ УРОК 8. ТЕМА: СЕМЬЯ\n\nКогда мы говорим о семье, нам важно знать базовый набор слов. Давай разберем их подробно и посмотрим, как называют близких сами носители языка в реальной жизни.\n\nГЛАВНЫЕ СЛОВА:\n\n• Mother [мáзэр] - Мать / Мама\nВ реальной жизни слово \"Mother\" звучит довольно официально (как слово \"Мать\" в юридических документах). Дома англичане почти всегда говорят Mom [мам] (в США) или Mum [мам] (в Англии).\n\n• Father [фáзэр] - Отец / Папа\nТо же самое: \"Father\" - это строго и официально. В кругу семьи всегда используют теплое слово Dad [дэд].\n\n• Parents [пэ́рэнтс] - Родители\nОтличное собирательное слово! Вместо того чтобы долго перечислять \"my mother and my father\", англичане просто говорят \"my parents\".\n\n• Sister [си́стэр] - Сестра\n• Brother [брáзэр] - Брат\n\n⚠️ СЕКРЕТ КРАСИВОГО ПРОИЗНОШЕНИЯ:\nВ словах mother, father, brother есть буквосочетание \"th\". Чтобы произнести его правильно, нужно слегка прикусить кончик языка зубами и сказать звонкий звук, похожий на русский \"з\". Не заменяй его на чистый звук \"в\" или \"з\", иначе получится классический школьный акцент!","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
