VALUES (
  8,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: РАЗГОВОР О БЛИЗКИХ\n\nДавай посмотрим, как разработчик Алекс показывает коллеге Анне фотографию на телефоне во время кофейного перерыва в офисе:\n\nAnna: Alex, who is on your screen? Is it your family?\nAlex: Yes! Look, these are my parents. My mother and my father.\nAnna: They look happy! And who is this girl?\nAlex: She is my sister. Her name is Liza.\nAnna: Do you have a brother?\nAlex: No, I don''t. I have a sister, but I don''t have a brother.\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nАнна: Алекс, кто это у тебя на экране? Это твоя семья?\nАлекс: Да! Смотри, это мои родители. Моя мама и мой папа.\nАнна: Они выглядят счастливыми! А кто эта девушка?\nАлекс: Это моя сестра. Ее зовут Лиза.\nАнна: А брат у тебя есть?\nАлекс: Нет. У меня есть сестра, но у меня нет брата.\n\n💡 КУЛЬТУРНЫЙ ЛАЙФХАК:\nВ английском языке есть потрясающее слово, которого очень не хватает в русском - это слово siblings [си́блингз]. Оно означает \"братья и сестры вместе взятые\". Если американец спросит тебя: \"Do you have any siblings?\", он просто хочет узнать, есть ли у тебя вообще родные братья или сестры, не угадывая их пол заранее!\n\n🔥 Твое мини-задание: Расскажи вслух о своей семье по нашей простой формуле. Например: \"I have a mother and a brother\". Назови своих близких прямо сейчас!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


