  content_json
)
VALUES (
  9,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-УРОК ОТ LEXI: МАГИЯ ЦИФР И ВОЗРАСТ\n\nПривет! На связи Lexi. Сегодня у нас супер-практичная тема, которая нужна буквально каждый день: числа от 1 до 100 и разговор о возрасте. \n\nПосчитать сдачу в магазине, назвать номер своего телефона, сказать, сколько тебе лет или спросить об этом коллегу - для всего этого нужны цифры.\n\nВключай короткое видео! Я научу Вас произносить числа так, чтобы иностранцы с первого раза понимали, говоришь ты \"15\" или \"50\". Это самая частая ловушка, и мы разберем ее на пальцах!","video_url":"https://vk.com/video-230370533_456239032","vk_attachment":"video-230370533_456239032","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  9,
  2,
  'theory',
  '{"text":"✨ УРОК 9. ЧИСЛА ОТ 1 ДО 100\n\nХорошая новость: чтобы считать до 100, не нужно учить сто разных слов. Достаточно понять логику конструктора!\n\nБАЗА (1 - 12):\nИх нужно просто запомнить.\n1 - one, 2 - two, 3 - three, 4 - four, 5 - five, 6 - six, 7 - seven, 8 - eight, 9 - nine, 10 - ten, 11 - eleven, 12 - twelve.\n\nПОДРОСТКИ (13 - 19):\nК числу просто добавляется окончание -TEEN [тин]. Ударение падает прямо на него!\n• 13 - thirteen [сёрти́н]\n• 14 - fourteen [форти́н]\n• 15 - fifteen [фифти́н] (обрати внимание: не fiveteen, а fifteen!)\n\nДЕСЯТКИ (20 - 90):\nЗдесь используется окончание -TY [ти]. Ударение всегда падает на ПЕРВЫЙ слог!\n• 20 - twenty [твэ́нти]\n• 30 - thirty [сёрти]\n• 40 - forty [фо́рти] (обрати внимание: буква \"u\" пропадает!)\n• 50 - fifty [фи́фти]\n\nКАК СОБРАТЬ ЛЮБОЕ ЧИСЛО?\nПросто соединяем десяток и единицу через дефис:\n• 21 - twenty-one\n• 35 - thirty-five\n• 99 - ninety-nine\n• 100 - a hundred [а ха́ндрэд]\n\n⚠️ ГЛАВНАЯ ЛОВУШКА НОВИЧКОВ:\nРазница между 15 и 50 только в ударении и хвостике! \n15 - fif-TEEN (тянем конец), 50 - FIF-ty (рубим в начале). Не путай их!","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  9,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: СКОЛЬКО ТЕБЕ ЛЕТ?\n\nДавай посмотрим, как на ИТ-митапе общаются два участника, обсуждая возраст и состав команды:\n\nBen: Hey! How old are you, Max?\nMax: Hi Ben! I am 15 years old. \nBen: Oh, really? You are very young! And how old is your team lead?\nMax: He is forty-five years old. He is very experienced. \nBen: Awesome. How many people are in your team?\nMax: There are twenty-five people in our team.\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nБен: Хэй! Сколько тебе лет, Макс?\nМакс: Привет, Бен! Мне 15 лет. (дословно: Я есть 15 лет старый)\nБен: О, правда? Ты очень молод! А сколько лет твоему тимлиду?\nМакс: Ему сорок пять лет. Он очень опытный.\nБен: Круто. А сколько человек в твоей команде?\nМакс: В нашей команде двадцать пять человек.\n\n💡 ВАЖНЫЙ РАЗГОВОРНЫЙ ЛАЙФХАК:\nВ английском языке фразу \"years old\" в конце говорить вообще не обязательно! Носители языка в 95% случаев сокращают ответ. \nВместо длинного \"I am fifteen years old\" они скажут просто: \"I''m 15\". И все их поймут!\n\n🔥 Твое мини-задание: Назови свой реальный возраст вслух на английском языке по короткой формуле: \"I''m ...\". Попробуй прямо сейчас!","button_text":"Перейти к тестов ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


