  step_type,
  content_json
)
VALUES (
  10,
  1,
  'theory',
  '{"text":"🎬 ФИНАЛЬНЫЙ ВИДЕО-УРОК С LEXI: ТВОЯ ПРЕЗЕНТАЦИЯ\n\nПоздравляю! Вы добрался до финала этого модуля. Вы проделал огромную работу: выучил приветствия, числа, страны, местоимения и укротил глагол to be. \n\nСегодня мы закроем главный пазл - научимся составлять лаконичный и уверенный текст о себе, который на международном рынке называется \"About me\" (Обо мне). Этот блок текста ты сможешь использовать в личных профилях, рабочих чатах или при знакомстве.\n\nВключай финальное видео от Lexi! Она расскажет, как связать все твои знания в один красивый рассказ, и даст заряд мотивации на будущее!","video_url":"https://vk.com/video-230370533_456239034","vk_attachment":"video-230370533_456239034","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  10,
  2,
  'theory',
  '{"text":"✨ УРОК 10. МАСТЕР-ШАБЛОН «ABOUT ME»\n\nРассказ о себе в английском языке строится как логичный конструктор. Давай разберем пошаговую структуру, где каждое предложение тебе уже знакомо:\n\n1. ПРИВЕТСТВИЕ (Задаем тон)\n• Hello! или Hi everyone! [хай э́уриуан] (Привет всем!)\n\n2. ИМЯ (Кто ты)\n• I''m Alex. или My name is Alex.\n\n3. СТРАНА И НАЦИОНАЛЬНОСТЬ (Откуда ты)\n• I''m from Russia. I''m Russian.\n\n4. ВОЗРАСТ (Цифры на практике)\n• I''m 37. (Короткий и самый живой вариант без \"years old\").\n\n5. ПРОФЕССИЯ ИЛИ СТАТУС (Чем занимаешься)\n• I am a manager. или I''m a developer. \n\n6. ФИНАЛЬНАЯ ВЕЖЛИВОСТЬ (Красивая точка)\n• Nice to meet you!\n\n💡 ОБРАТИ ВНИМАНИЕ:\nПосмотри, как часто здесь работает глагол to be в форме \"I am\" / \"I''m\". Без него этот текст просто развалился бы на части! Именно поэтому мы так подробно учили его в прошлых уроках.","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  10,
  3,
  'theory',
  '{"text":"📖 РЕАЛЬНЫЙ ПРИМЕР: ТЕКСТ ДЛЯ ПРОФИЛЯ\n\nДавай посмотрим, как выглядит готовая визитка-презентация, которую можно отправить в рабочий чат или разместить в описании своего профиля:\n\n\"Hello! My name is Aleksey. I''m from Russia. I am 37 years old. I''m a specialist. Nice to meet you!\"\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\n\"Привет! Меня зовут Алексей. Я из России. Мне 37 лет. Я специалист. Приятно познакомиться!\"\n\n💡 ПОЛЕЗНЫЙ ЛАЙФХАК ДЛЯ ПИСЬМА:\nКогда ты пишешь текст \"About me\" в мессенджерах, разделяй его на небольшие абзацы или используй списки с эмодзи в начале строк (как в наших уроках). Сплошной текст тяжело читать с экрана телефона, а структурированная визитка сразу покажет тебя как профессионала.\n\n🔥 Твое финальное супер-задание: Возьми этот шаблон, подставь в него свое имя, свой возраст и профессию. Прочитай получившийся текст вслух перед зеркалом 3 раза. Ты только что заговорил на английском о себе!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


