INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  11,
  1,
  'theory',
  '{"text":"🎬 НОВЫЙ ЭТАП С LEXI: ВРЕМЯ НАСТОЯЩИХ ДЕЙСТВИЙ\n\nПривет! Ты отлично освоил глагол-связку to be. Но что делать, если в предложении появляется реальное действие? Например: я работаю, ты учишься, мы играем. \n\nДля этого в английском языке есть главное и самое популярное время - Present Simple (Презент Симпл), или простое настоящее время. Мы используем его каждый раз, когда рассказываем о своей рутине, привычках, хобби или работе.\n\nВключайте короткое видео от Lexi! Она расскажет, почему Present Simple - это самое легкое время в английском, и как строить предложения на автомате, используя всего одно простое правило.","video_url":"https://vk.com/video-230370533_456239035","vk_attachment":"video-230370533_456239035","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  11,
  2,
  'theory',
  '{"text":"✨ УРОК 11. НАСТОЯЩЕЕ ВРЕМЯ: PRESENT SIMPLE\n\nМы используем Present Simple, когда действие происходит вообще, регулярно, каждый день или часто. Это не то, что ты делаешь прямо в эту секунду, а то, что ты делаешь ПО ЖИЗНИ.\n\nГЛАВНЫЙ СЕКРЕТ ДЛЯ ОКОНЧАНИЙ:\nВ русском языке мы постоянно меняем окончания глаголов: я работаЮ, ты работаЕШЬ, мы работаЕМ, они работа ЮТ. Нужно учить кучу форм!\n\nВ английском языке для местоимений I (Я), You (Ты/Вы), We (Мы), They (Они) все ГОРАЗДО ПРОЩЕ. Глагол вообще НЕ МЕНЯЕТСЯ! Мы просто берем его прямо из словаря в чистом виде.\n\nФОРМУЛА: КТО + ЧИСТЫЙ ГЛАГОЛ\n\nДавай посмотрим на примеры:\n• I work [ай уёрк] - Я работаю.\n• You study [ю ста́ди] - Ты учишься / Вы учитесь.\n• We play [уи плэй] - Мы играем.\n• They live [зэй лив] - Они живут.\n\nВидишь? Никаких окончаний, никаких лишних букв в конце. Просто берешь слово и ставишь после местоимения!","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  11,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: РАЗГОВОР О ПРИВЫЧКАХ\n\nПосмотри, как общаются два разработчика в ИТ-коворкинге, обсуждая свой обычный рабочий день и хобби:\n\nMax: Hi Sam! I work in this office every day. И you?\nSam: Hi Max! I work here too. We share this desk!\nMax: Cool. What do you do after work?\nSam: My friends and I play video games. We play every weekend. \nMax: Awesome! My sister and I study English. We study every evening.\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nМакс: Привет, Сэм! Я работаю в этом офисе каждый день. А ты?\nСэм: Привет, Макс! Я тоже здесь работаю. Мы делим этот стол!\nМакс: Круто. Чем занимаешься после работы?\nСэм: Мы с друзьями играем в видеоигры. Мы играем каждые выходные.\nМакс: Круто! Мы с сестрой учим английский. Мы учимся каждый вечер.\n\n💡 СЛОВА-ПОДКАЗЧИКИ (ТАЙМ-МАРКЕРЫ):\nВ Present Simple есть слова, которые так и кричат, что действие регулярное. Запомни их:\n• every day [э́ури дэй] - каждый день\n• every evening [э́ури и́внинг] - каждый вечер\n• every weekend [э́ури уикэ́нд] - каждые выходные\n\n🔥 Твое мини-задание: Расскажи о своем дне, используя чистые глаголы. Скажи вслух фразу: \"I work every day\" или \"I study every day\". Привыкай к простоте английской грамматики!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


