INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  12,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-УРОК ОТ LEXI:МАГИЯ БУКВЫ S\n\nПривет! В прошлом уроке мы радовались тому, как просто строить настоящее время Present Simple для слов я, ты, мы, они. Там глагол оставался чистым.\n\nНо сегодня мы переходим к троице He (Он), She (Она), It (Оно). И здесь включается самое известное правило английской грамматики, на котором спотыкаются даже продвинутые студенты. Это магия окончания -S.\n\nВключайте короткое видео! Lexi покажет на примерах, как этот маленький хвостик меняет глаголы, и научит вас замечать его на автомате, чтобы Ваша речь звучала грамотно и профессионально.","video_url":"https://vk.com/video-230370533_456239036","vk_attachment":"video-230370533_456239036","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  12,
  2,
  'theory',
  '{"text":"✨ УРОК 12. НАСТОЯЩЕЕ ВРЕМЯ ДЛЯ HE, SHE, IT\n\nЗапомни железное правило: в Present Simple, если действие совершает ОН, ОНА или ОНО, к глаголу в 100% случаев нужно прибавить окончание -S или -ES. \n\nЭто единственное изменение глагола во всем времени, но англичане за него очень держатся!\n\nДАВАЙ ПОСМОТРИМ НА НАШИ ПРИМЕРЫ:\n\n• He works [хи уёркс] - Он работает.\n(Сравни: I work, но He works)\n\n• It helps [ит хэлпс] - Это помогает.\n(Например, этот софт или этот лайфхак помогает тебе в работе)\n\n⚠️ ЛОВУШКА С ПРАВОПИСАНИЕМ (STUDIES):\nЕсли глагол заканчивается на букву -y, а перед ней стоит согласная буква, то при добавлении нашего хвостика буква -y превращается в -ie!\n• She studies [ши ста́диз] - Она учится.\n(Слово study превратилось в studies. Произносится мягко, как з на конце).\n\nПросто запомни эту визуальную форму:\nHe works. She studies. It helps.","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  12,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: ОБСУЖДАЕМ КОЛЛЕГУ\n\nДавай послушаем разговор двух сотрудников в ИТ-офисе. Они обсуждают свою новую коллегу Марину и рабочий инструмент:\n\nSam: Sofia, do you know Marina? \nSofia: Yes! She works in our team now. She''s a senior developer.\nSam: Oh, awesome. Does she live in Moscow?\nSofia: No, she lives in Solnechnogorsk, but she travels to Moscow often.\nSam: Great. And what about our new AI tool?\nSofia: It helps a lot! It works perfectly.\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nСэм: София, ты знаешь Марину?\nСофия: Да! Она теперь работает в нашей команде. Она старший разработчик. (в оригинале - She works)\nСэм: О, круто. Она живет в Москве?\nСофия: Нет, она живет в Солнечногорске, но часто ездит в Москву. (she lives, she travels)\nСэм: Отлично. А как насчет нашего нового ИИ-инструмента?\nСофия: Он очень помогает! Он работает идеально. (It helps, It works)\n\n💡 ГРАММАТИЧЕСКИЙ ЛАЙФХАК:\nПомни из урока про местоимения, что любое неодушевленное приложение, программа или гаджет - это \"It\". Поэтому, если ты хочешь сказать \"Код работает\" или \"Программа помогает\", ты тоже используешь окончание -s: The code works, The program helps!\n\n🔥 Твое мини-задание: Подумай о любом своем друге или коллеге и скажи вслух, где он или она работает, используя окончание -s. Например: \"He works in an office\" или \"She works at home\". Прокачай этот навык вслух!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


