  step_type,
  content_json
)
VALUES (
  13,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-БЛОГ ОТ LEXI: ТВОЙ ОБЫЧНЫЙ ДЕНЬ\n\nПривет! На связи Лекси. Сегодня мы разберем тему, которая превратит Вашу сухую грамматику в живой и плавный рассказ. Мы поговорим о распорядке дня (Daily Routine).\n\nПроснулись, пошли на учебу или работу, перекусили, легли спать - это те кирпичики, из которых состоит жизнь любого человека на планете. Освоив эти фразы, вы сможете легко поддержать беседу о привычках и графике.\n\nВключайте видео! Мы разберем, как правильно соединять глаголы расписания с уже изученным временем Present Simple, и отработаем произношение до автоматизма.","video_url":"https://vk.com/video-230370533_456239037","vk_attachment":"video-230370533_456239037","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  13,
  2,
  'theory',
  '{"text":"✨ УРОК 13. РАСПОРЯДОК ДНЯ И РУТИНА\n\nЧтобы описать свой день, нам понадобятся 5 базовых глаголов действия. Давай разберем их и сразу вспомним наши правила Present Simple!\n\nТВОЙ НАБОР НА КАЖДЫЙ ДЕНЬ:\n\n• Wake up [уэйк ап] - просыпаться / открывать глаза.\nПример: I wake up early. (Я просыпаюсь рано).\n\n• Go to school [гоу ту скул] - идти в школу / учиться.\nПример: You go to school. (Ты ходишь в школу).\n\n• Work [уёрк] - работать.\nПример: We work every day. (Мы работаем каждый день).\n\n• Eat [ит] - есть / кушать.\nПример: They eat pizza. (Они едят пиццу).\n\n• Sleep [слип] - спать.\nПример: I sleep 8 hours. (Я сплю 8 часов).\n\n⚠️ ВСПОМИНАЕМ ГЛАВНУЮ ЛОВУШКУ HE / SHE / IT:\nЕсли день описываешь не ты сам, а твой друг, брат или сестра, не забывай добавлять окончание -S к глаголу!\n• He wakes up [хи уэйкс ап] - Он просыпается.\n• She goes to school [ши гоуз ту скул] - Она ходит в школу (у слова go окончание превращается в -es).\n• It works [ит уёркс] - Это работает.","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
