INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  14,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-СЕКРЕТ ОТ LEXI: КАК ЧАСТО?\n\nПривет! На связи Lexi. Вы уже умеете описывать свой распорядок дня и говорить о действиях в Present Simple. Но чтобы ваша речь звучала еще точнее и интереснее, нужно добавить один важный элемент - частотные слова.\n\nКак часто вы пьете кофе по утрам? Всегда? Часто? Или, может быть, никогда? Именно эти слова делают язык живым и помогают детально описать ваши привычки.\n\nВключайте наше короткое видео! Я помогу вам разобраться с правильным произношением этих слов и раскрою главный секрет: в какое именно место в предложении их нужно ставить, чтобы не совершить глупую ошибку.","video_url":"https://vk.com/video-230370533_456239038","vk_attachment":"video-230370533_456239038","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  14,
  2,
  'theory',
  '{"text":"✨ УРОК 14. ЧАСТОТНЫЕ СЛОВА (НАРЕЧИЯ ЧАСТОТЫ)\n\nЭти слова - лучшие друзья времени Present Simple. Они показывают регулярность наших действий. Давай разберем их от самых частых к самым редким:\n\n• Always [óлуэйз] - Всегда (100% случаев)\nПример: I always wake up early. (Я всегда просыпаюсь рано).\n\n• Usually [ю́жуали] - Обычно (80% случаев)\nПример: You usually work from home. (Ты обычно работаешь из дома).\n\n• Often [о́фн] - Часто (60% случаев)\nПример: We often eat pizza. (Мы часто едим пиццу).\n💡 Секрет: буква t в слове often не произносится!\n\n• Sometimes [са́мтаймз] - Иногда (30% случаев)\nПример: They sometimes play games. (Они иногда играют в игры).\n\n• Never [нэ́уэр] - Никогда (0% случаев)\nПример: I never sleep in the office. (Я никогда не сплю в офисе).\n\n⚠️ ГЛАВНОЕ ПРАВИЛО МЕСТА В ПРЕДЛОЖЕНИИ:\nЗапомни: эти слова всегда ставятся ПЕРЕД основным глаголом-действием! \nМы говорим: I always work (Частотное слово + Глагол). Ставить их в самый конец предложения - грубая ошибка.","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  14,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: СЕКРЕТЫ ПРОДУКТИВНОСТИ\n\nДавай послушаем, как менеджер Сэм и аналитик Кейт обсуждают свои рабочие привычки в ИТ-компании:\n\nSam: Kate, you look fresh! Do you always wake up early?\nKate: Hi Sam! Yes, I always wake up at 6 AM. I usually run in the morning.\nSam: Wow! I never run in the morning. I sometimes work at night, so I''m often tired.\nKate: Oh, that''s bad. Our team lead never works at night. He usually sleeps 8 hours!\nSam: He is lucky! I usually drink 5 cups of coffee.\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nСэм: Кейт, отлично выглядишь! Ты всегда просыпаешься рано?\nКейт: Привет, Сэм! Да, я всегда просыпаюсь в 6 утра. Я обычно бегаю по утрам.\nСэм: Вау! Я никогда не бегаю по утрам. Я иногда работаю по ночам, поэтому часто устаю.\nКейт: О, это плохо. Наш тимлид никогда не работает по ночам. Он обычно спит 8 часов!\nСэм: Ему везет! Я обычно пью 5 чашек кофе.\n\n💡 КРИТИЧЕСКАЯ ЛОВУШКА ДЛЯ РУССКИХ (СЛОВО NEVER):\nВ русском языке мы используем двойное отрицание: \"Я НИКОГДА НЕ работаю\". Два раза говорим \"нет\".\nВ английском языке двойное отрицание ЗАПРЕЩЕНО. Слово \"never\" уже само по себе отрицательное. Поэтому после него глагол всегда идет в обычном, утвердительном виде!\nПравильно: I never work (дословно: Я никогда работаю). Не добавляй туда никаких лишних отрицаний!\n\n🔥 Твое мини-задание: Составь предложение про себя со словом \"always\" или \"never\". Скажи его вслух прямо сейчас!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


