INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  15,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-ПРАКТИКА С LEXI: СВЯЗНЫЙ РАССКАЗ О СЕБЕ\n\nПривет! Вы выучили глаголы рутины и частотные слова. Сегодня финальный аккорд этой большой темы - мы объединим все кусочки мозаики в один плавный, красивый рассказ о своем дне.\n\nВы научитесь уверенно отвечать на один из самых популярных вопросов при знакомстве: What do you do every day? (Что ты делаешь каждый день?).\n\nПосмотрите короткое видео от Lexi! Она покажет, как правильно использовать слова-связки, чтобы ваш рассказ не звучал как сухой список дел, а лился как естественная, живая речь настоящего носителя.","video_url":"https://vk.com/video-230370533_456239039","vk_attachment":"video-230370533_456239039","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  15,
  2,
  'theory',
  '{"text":"✨ УРОК 15. КОНСТРУКТОР РАССКАЗА «МОЙ ДЕНЬ»\n\nКогда иностранец спрашивает: \"What do you do every day?\", он хочет услышать небольшую историю о твоей жизни. Чтобы рассказ звучал красиво, нам понадобятся слова-переходы (connectors). Они связывают действия во времени.\n\nЗАПОМНИ ЭТИ ТРИ СЛОВА:\n\n• Then [зэн] - Затем / Потом\n• After that [а́фтэр зэт] - После этого\n• Finally [фа́йнали] - В конце концов / Наконец\n\nФОРМУЛА ИДЕАЛЬНОГО ПРЕДЛОЖЕНИЯ:\nВремя суток + Частотное слово + Действие\n\nПосмотри, как круто эти элементы оживляют простые глаголы:\nIn the morning I usually wake up at 7 AM. Then I work. (Утром я обычно просыпаюсь в 7 утра. Затем я работаю).\n\nБез слов \"usually\" и \"then\" речь звучала бы обрывисто, как у робота!","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  15,
  3,
  'theory',
  '{"text":"📖 РЕАЛЬНЫЙ ТЕКСТ: МОНОЛОГ О СВОЕМ ДНЕ\n\nПосмотри, какой классный и лаконичный текст \"My Day\" получился у нашего студента. Это твой готовый шаблон для общения:\n\n\"Every day I wake up early. In the morning I always drink coffee and then I work. After that I usually eat with my friends. In the evening we sometimes play video games. Finally, I sleep 8 hours.\"\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\n\"Каждый день я просыпаюсь рано. Утром я всегда пью кофе, а затем работаю. После этого я обычно ем со своими друзьями. Вечером мы иногда играем в видеоигры. Наконец, я сплю 8 часов.\"\n\n💡 ВАЖНЫЙ СЛОВАРНЫЙ ЛАЙФХАК:\nОбрати внимание на фразы про время суток. Они всегда используются с предлогом \"in\" и артиклем \"the\":\n• In the morning - Утром\n• In the afternoon - Днем\n• In the evening - Вечером\nИсключение только одно: ночью мы говорим At night [эт найт]. Запомни это маленькое правило!\n\n🔥 Твое мини-задание: Скажи вслух, что ты делаешь утром, используя связку \"then\". Например: \"In the morning I wake up, then I work\".","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


