)
VALUES (
  16,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-УРОК С LEXI: СЕКРЕТ ВОПРОСИТЕЛЬНЫХ ПРЕДЛОЖЕНИЙ\n\nПривет! На связи Лекси. Вы уже умеете говорить \"Я счастлив\" или \"Она программист\". Но как спросить собеседника об этом?\n\nВ русском языке мы просто меняем интонацию: \"Ты готов.\" превращается в \"Ты готов?\". Сами слова остаются на своих местах. В английском языке правила другие - здесь нужно физически переставлять слова в предложении.\n\nВключай короткое видео! Я покажу Вам, как легко работает фокус с перестановкой слов, и мы разберем самые популярные вопросы, которые пригодятся Вам на любой встрече, созвоне или в путешествии.","video_url":"https://vk.com/video-230370533_456239040","vk_attachment":"video-230370533_456239040","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  16,
  2,
  'theory',
  '{"text":"✨ УРОК 16. ВОПРОСЫ С ГЛАГОЛОМ TO BE\n\nГлагол to be (am, is, are) - парень очень гордый и сильный. Когда мы хотим задать вопрос, ему не нужны никакие помощники. Он просто берет и перепрыгивает через человека на самое первое место в предложении!\n\nСРАВНИ УТВЕРЖДЕНИЕ И ВОПРОС:\n\n1. Спрашиваем про готовность:\n• Утверждение: You are ready [ю ар рэ́ди] - Ты готов.\n• Вопрос: Are you ready? [ар ю рэ́ди] - Ты готов?\n(Форма are просто встала перед местоимением you).\n\n2. Спрашиваем про людей вокруг:\n• Утверждение: She is your friend [ши из юэ фрэнд] - Она твоя подруга.\n• Вопрос: Is she your friend? [из ши юэ фрэнд] - Она твоя подруга?\n(Форма is послушно перепрыгнула на первое место).\n\n3. Спрашиваем про себя:\n• Утверждение: I am late [ай эм лэйт] - Я опоздал.\n• Вопрос: Am I late? [эм ай лэйт] - Я опоздал?\n\nФОРМУЛА ЛЮБОГО ТАКОГО ВОПРОСА:\nAm / Is / Are + Кто совершает действие + Какой / Кто / Где?","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  16,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: ПЕРЕД НАЧАЛОМ МИТИНГА\n\nДавай посмотрим, как менеджер Джон и разработчик Алекс общаются на кухне офиса прямо перед началом важного рабочего созвона:\n\nJohn: Alex, hello! Are you ready for the meeting?\nAlex: Hi John! Yes, I am. Am I late?\nJohn: No, you are on time. Look, who is that girl over there? Is she your friend?\nAlex: No, she is not. She is our new designer. Is she ready too?\nJohn: Yes, she is. Let''s go!\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nДжон: Алекс, привет! Ты готов к встрече?\nАлексей: Привет, Джон! Да, готов. Я опоздал?\nДжон: Нет, ты вовремя. Посмотри, кто та девушка вон там? Она твоя подруга?\nАлексей: Нет. Она наш новый дизайнер. Она тоже готова?\nДжон: Да, она готова. Пошли!\n\n💡 СЕКРЕТ КОРОТКИХ И ВЕЖЛИВЫХ ОТВЕТОВ:\nВ английском языке считается не очень вежливым на вопрос отвечать просто одиноким словом \"Yes\" или \"No\". Это звучит слишком сухо. Носители всегда добавляют короткий грамматический хвостик:\n• На вопрос \"Are you ready?\" мы отвечаем: Yes, I am или No, I''m not.\n• На вопрос \"Is she happy?\" мы отвечаем: Yes, she is или No, she''s not.\n\n🔥 Твое мини-задание: Задай вопрос своему телефону или компьютеру вслух прямо сейчас: \"Are you ready?\". Потренируй эту вопросительную интонацию с перестановкой глагола!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


