INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  17,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-УРОК ОТ LEXI: СИЛА ОТРИЦАНИЯ\n\nПривет! На связи Lexi. В прошлых уроках мы научились утверждать и задавать вопросы. Сегодня мы освоим третий важнейший элемент речи - отрицания.\n\nКак сказать, что сервер не работает, коллега не в офисе, или ты сам совсем не устал после долгого рабочего дня? Для этого нам понадобится всего одна маленькая, но очень сильная частица.\n\nВключайте короткое видео! Мы разберем, как строить отрицания с глаголом to be, и научимся использовать крутые разговорные сокращения, которые обожают носители языка.","video_url":"https://vk.com/video-230370533_456239041","vk_attachment":"video-230370533_456239041","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  17,
  2,
  'theory',
  '{"text":"✨ УРОК 17. ОТРИЦАНИЯ С ГЛАГОЛОМ TO BE\n\nЧтобы сделать предложение отрицательным, нам не нужно учить сложные правила. Достаточно взять отрицательную частицу NOT [нот] (не) и поставить ее строго ПОСЛЕ нашего глагола to be (am, is, are).\n\nФОРМУЛА: КТО + AM / IS / ARE + NOT + КАКОЙ / ГДЕ / КТО\n\nДавай разберем наши главные примеры:\n• I am not tired [ай эм нот тáйэд] - Я не устал.\n• He is not here [хи из нот хи́ар] - Он не здесь / Его нет тут.\n• They are not ready [зэй ар нот рэ́ди] - Они не готовы.\n\nРАЗГОВОРНЫЕ СОКРАЩЕНИЯ:\nВ живой речи иностранцы почти всегда сокращают частицу NOT, сливая ее с глаголом:\n• Is not - isn''t [изнт] (He isn''t here)\n• Are not - aren''t [арнт] (They aren''t ready)\n\n⚠️ КРИТИЧЕСКОЕ ИСКЛЮЧЕНИЕ ДЛЯ ФОРМЫ AM:\nФорма глагола \"am\" никогда не сливается со словом not в одно слово \"amnot\" - такого монстра в английском языке просто нет! В случае с собой мы просто сокращаем местоимение: I''m not tired [айм нот тáйэд].","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  17,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: ПОИСКИ В ОФИСЕ\n\nДавай заглянем в ИТ-отдел и послушаем, как менеджер Анна и дизайнер Сэм ищут коллегу прямо перед началом важного рабочего созвона:\n\nAnna: Sam, hello! Is Alex in the office? \nSam: Hi Anna! No, he is not here. He works from home today.\nAnna: Oh, bad luck. Are you ready for the presentation?\nSam: Yes, I am. I''m not tired, and the project is perfect!\nAnna: Great! Our clients are not late, they are in the chat room now. Let''s start!\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nАнна: Сэм, привет! Алекс в офисе?\nСэм: Привет, Анна! Нет, его здесь нет. Он сегодня работает из дома.\nАнна: О, какая неудача. Ты готов к презентации?\nСэм: Да, готов. Я не устал, и проект идеален!\nАнна: Отлично! Наши клиенты не опаздывают, они уже в комнате чата. Давайте начинать!\n\n💡 ПОЛЕЗНЫЙ ЯЗЫКОВОЙ ЛАЙФХАК:\nДля форм \"is not\" и \"are not\" в разговорном английском есть два абсолютно равноправных способа сокращения. Ты можешь сказать:\n1. He isn''t / They aren''t (сокращаем глагол + not)\n2. He''s not / They''re not (сокращаем местоимение + глагол)\nОба варианта звучат естественно, выбирай любой!\n\n🔥 Твое mini-задание: Скажи вслух фразу \"Я не устал\", используя короткую форму: \"I''m not tired\". Почувствуй себя уверенно!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


