INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  18,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-РАЗБОР С LEXI: СЕКРЕТ КЛАССНЫХ ВОПРОСОВ\n\nПривет! На связи Lexi. Вы уже умеете говорить о своих привычках и регулярных действиях в настоящем времени. Но как спросить собеседника об этом? Настало время научиться задавать вопросы в Present Simple!\n\nХотите узнать, нравится ли иностранцу английский язык? Или работает ли его коллега удаленно? В отличие от русского языка, здесь мало просто изменить интонацию в конце предложения. Придется призвать на помощь специальных помощников.\n\nВключайте короткое видео! Мы разберем секретное оружие английских вопросов - глаголы Do и Does, и ты поймешь, как строить их легко и без долгих раздумий.","video_url":"https://vk.com/video-230370533_456239042","vk_attachment":"video-230370533_456239042","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  18,
  2,
  'theory',
  '{"text":"✨ УРОК 18. ВОПРОСЫ В PRESENT SIMPLE\n\nВ английском языке обычные глаголы действия (like, work, study) слишком слабые, чтобы самостоятельно сделать вопрос. Им обязательно нужны глаголы-помощники, которые встают на самое первое место в предложении.\n\nЗНАКОМЬСЯ С ДВУМЯ ГЛАВНЫМИ ПОМОЩНИКАМИ:\n\n1. Помощник DO [ду]\nРаботает с местоимениями: I, You, We, They.\nФОРМУЛА: Do + кто + чистый глагол?\nПример: Do you like English? [ду ю лайк и́нглиш] - Тебе нравится английский?\n\n2. Помощник DOES [даз]\nРаботает с местоимениями: He, She, It.\nФОРМУЛА: Does + кто + чистый глагол?\nПример: Does she work? [даз ши уёрк] - Она работает?\n\n⚠️ ГЛАВНАЯ ЛОВУШКА ВСЕХ НОВИЧКОВ:\nВспомни урок 12: в утверждениях для He/She/It мы добавляли к глаголу окончание -s (She works). Но в вопросе помощник Does настолько силен, что ЗАБИРАЕТ это окончание себе! Сам глагол действия снова становится абсолютно чистым.\n\n• Правильно: Does she work?\n• Ошибка: Does she works? (Буква s уже ушла в Does, два раза добавлять ее нельзя!)","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  18,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: РАЗГОВОР НА ИТ-МИТАПЕ\n\nДавай послушаем, как тестировщик Макс расспрашивает разработчика Бена о его проекте и команде в кулуарах конференции:\n\nMax: Ben, do you like your new project?\nBen: Yes, I do! It is very interesting.\nMax: Cool. Does your wife work with you?\nBen: No, she doesn''t. She studies at university. Do you know her?\nMax: No, I don''t. Do they play video games after work in your team?\nBen: Yes, they do. We always play together!\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nМакс: Бен, тебе нравится твой новый проект?\nБен: Да, очень! Он очень интересный.\nМакс: Круто. Твоя жена работает с тобой? (в оригинале - Does your wife work)\nБен: Нет. Она учится в университете. Ты ее знаешь?\nМакс: Нет. В вашей команде играют в видеоигры после работы?\nБен: Да. Мы всегда играем вместе!\n\n💡 КУЛЬТУРНЫЙ ЛАЙФХАК: ОТВЕЧАЙ КАК НОСИТЕЛЬ\nОтвечать на вопросы одиночными словами \"Yes\" или \"No\" в английском считается грубым. Всегда используй короткий вежливый ответ, возвращая глагол-помощник:\n• Do you like...? - Yes, I do. / No, I don''t.\n• Does she work...? - Yes, she does. / No, she doesn''t.\n\n🔥 Твое мини-задание: Задай вслух вопрос своему воображаемому собеседнику: \"Do you like English?\". И сами же ответь себе с улыбкой: \"Yes, I do!\". Почувствуй правильную интонацию!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


