INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  19,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-УРОК ОТ LEXI: ИСКУССТВО ГОВОРИТЬ «НЕТ»\n\nПривет! На связи Lexi. В прошлом уроке мы научились задавать вопросы и познакомились с глаголами-помощниками Do и Does. Сегодня мы призовем их снова, но уже для другой важной миссии - научиться строить отрицания.\n\nКак сказать, что Вы не знаете ответа на вопрос, ваш коллега не играет в игры по вечерам, или вы не работаете по выходным? В английском языке нельзя просто подставить частицу «не» перед действием. Нам снова понадобятся наши верные ассистенты.\n\nВключайте короткое видео! Мы разберем, как Do и Does помогают нам отказываться и отрицать, а также раскроем секрет, почему английское отрицание гораздо проще и логичнее русского.","video_url":"https://vk.com/video-230370533_456239043","vk_attachment":"video-230370533_456239043","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  19,
  2,
  'theory',
  '{"text":"✨ УРОК 19. ОТРИЦАНИЯ В PRESENT SIMPLE\n\nВ настоящем времени, чтобы сказать «не делаю», мы берем уже знакомых помощников Do и Does, добавляем к ним отрицательную частицу NOT и ставим эту конструкцию строго ПЕРЕД глаголом действия.\n\nДАВАЙ РАЗБЕРЕМ ДВЕ НАШИ ФОРМУЛЫ:\n\n1. Для компании I, You, We, They:\nИспользуем DO + NOT. В разговорной речи это всегда сокращается до DON''T [доунт].\nФОРМУЛА: Кто + don''t + чистый глагол\nПример: I don''t know [ай доунт ноу] - Я не знаю.\n\n2. Для троицы He, She, It:\nИспользуем DOES + NOT. В живой беседе это всегда превращается в DOESN''T [да́знт].\nФОРМУЛА: Кто + doesn''t + чистый глагол\nПример: He doesn''t play [хи да́знт плэй] - Он не играет.\n\n⚠️ ВАЖНЕЙШИЙ ГРАММАТИЧЕСКИЙ ЗАКОН:\nПомнишь, как в вопросах помощник Does забирал себе окончание -s у глагола? В отрицаниях происходит точно то же самое! Помощник doesn''t настолько силен, что напрочь стирает окончание -s у последующего действия.\n\n• Правильно: She doesn''t work.\n• Ошибка: She doesn''t works. (Буква s уже «съедена» помощником doesn''t, второй раз она не нужна!)","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  19,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: ОБСУЖДАЕМ ПЛАНЫ\n\nДавай заглянем в ИТ-офис во время обеденного перерыва и послушаем, как дизайнер Кейт и аналитик Сэм обсуждают привычки своего нового коллеги:\n\nKate: Sam, do you know our new developer, Alex?\nSam: No, I don''t know him well. Why?\nKate: He is very quiet. He doesn''t play video games with us and he doesn''t drink coffee!\nSam: Oh, really? We always drink coffee! Maybe he likes tea?\nKate: I don''t know. But he works very fast, and his code doesn''t have any errors!\nSam: Wow! That is the most important thing!\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nКейт: Сэм, ты знаешь нашего нового разработчика Алекса?\nСэм: Нет, я не знаю его хорошо. А что? (в оригинале - I don''t know)\nКейт: Он очень тихий. Он не играет в видеоигры с нами и не пьет кофе! (he doesn''t play, he doesn''t drink)\nСэм: О, правда? Мы-то всегда пьем кофе! Может, он любит чай?\nКейт: Я не знаю. Но он работает очень быстро, и его код не имеет ошибок! (code doesn''t have)\nСэм: Вау! Это самое главное!\n\n💡 СУПЕР-ЛАЙФХАК: БАН НА ДВОЙНОЕ ОТРИЦАНИЕ\nВ русском языке мы обожаем двойное отрицание: «Я НИКОГДА НЕ знаю». В английском это строго запрещено! Если в предложении уже стоит don''t или doesn''t, никаких других отрицаний быть не может. Одно предложение - одно отрицание!\n\n🔥 Твое мини-задание: Подумай о том, чего ты не делаешь по утрам, и скажи это вслух. Например: «I don''t drink tea» (Я не пью чай) или «I don''t play games». Сделай это прямо сейчас!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
