INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  20,
  1,
  'theory',
  '{"text":"🎬 ФИНАЛЬНЫЙ СЕКРЕТ СЛОВАРЯ ОТ LEXI\n\nПривет! На связи Lexi. Вы уже проделали колоссальный путь: умеете строить утверждения, отрицания и задавать вопросы двух разных типов. Сегодня мы разберем финальный штрих, который мгновенно превратит Вашу речь из ученической в естественную. Мы научимся давать короткие ответы.\n\nВ русском языке на вопрос \"Ты любишь кофе?\" мы просто отвечаем \"Да\" или \"Нет\". Но если Вы скажете иностранцу просто одинокое \"Yes\" или \"No\", это прозвучит для него как резкий отказ общаться или даже грубость.\n\nВключай короткое видео! Я расскажу Вам про главное эхо-правило английского языка, благодаря которому Вы начнете отвечать вежливо, красиво и на автомате.","video_url":"https://vk.com/video-230370533_456239044","vk_attachment":"video-230370533_456239044","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  20,
  2,
  'theory',
  '{"text":"✨ УРОК 20. ЭХО-ПРАВИЛО КОРОТКИХ ОТВЕТОВ\n\nВ английском языке короткий ответ строится по гениальному и простому закону, который лингвисты называют эхо-правилом: каким глаголом собеседник начал свой вопрос, точно такой же глагол должен прозвучать в конце твоего ответа!\n\nДАВАЙ РАЗБЕРЕМ ДВЕ НАШИ ГЛАВНЫЕ ГРУППЫ:\n\n1. Если вопрос начался с глагола TO BE (am, is, are):\nСлышим в начале Is или Are - возвращаем их же в конце!\n• Are you ready? (Ты готов?) - Yes, I am. / No, I''m not.\n• Is she your friend? (Она твоя подруга?) - Yes, she is. / No, she isn''t.\n\n2. Если вопрос начался с помощников PRESENT SIMPLE (do, does):\nСлышим в начале Do или Does - зеркально отражаем их!\n• Do you like English? (Тебе нравится английский?) - Yes, I do. / No, I don''t.\n• Does he play games? (Он играет в игры?) - Yes, he does. / No, he doesn''t.\n\nПросто прислушайся к первому слову вопроса, и у тебя в руках готовый ответ!","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  20,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: СОЗВОР С КЛИЕНТОМ\n\nПосмотри, как менеджер Макс обсуждает готовность проекта с зарубежным заказчиком Томом. Обрати внимание, как вежливо звучат их ответы:\n\nTom: Hi Max! Is your team lead in the office today?\nMax: Hello Tom! Yes, he is. He is at his desk.\nTom: Great. Do you have the new code ready?\nMax: Yes, I do. It works perfectly.\nTom: Awesome. Is the designer busy now?\nMax: No, she isn''t. She is free.\nTom: Perfect, let''s start our meeting!\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nТом: Привет, Макс! Твой тимлид сегодня в офисе?\nМакс: Привет, Том! Да, он на месте. Он за своим столом. (в оригинале - Yes, he is)\nТом: Отлично. У тебя готов новый код?\nМакс: Да, готов. Он работает идеально. (в оригинале - Yes, I do)\nТом: Супер. Дизайнер сейчас занята?\nМакс: Нет, она свободна. (в оригинале - No, she isn''t)\nТом: Прекрасно, давайте начинать нашу встречу!\n\n💡 КУЛЬТУРНЫЙ ЛАЙФХАК:\nПочему англичане так делают? Для них одинокое \"Yes\" звучит как на допросе в полиции, сухо и неприветливо. Добавление хвостика \"I am\" или \"I do\" показывает собеседнику, что ты вовлечен в разговор, уважаешь его и настроен на дружелюбную беседу.\n\n🔥 Твое мини-задание: Представь, что я спрашиваю тебя: \"Do you study English every day?\". Ответь мне вслух гордо и вежливо: \"Yes, I do!\".","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


