INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  21,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-УРОК ОТ LEXI: РАССТОЯНИЕ И КОЛИЧЕСТВО\n\nПривет! На связи Lexi. Представьте ситуацию: вам нужно попросить коллегу передать вон тот документ, показать на свой ноутбук или объяснить, чьи это чашки на столе. \n\nВ русском языке мы просто говорим \"этот\", \"тот\", \"эти\" или \"те\". В английском для этого есть четыре специальных слова, выбор которых напоминает простую математическую матрицу. Он зависит всего от двух вещей: сколько предметов и как далеко они от вас находятся.\n\nВключайте короткое видео! Мы разберем эту тему на наглядных примерах, отработаем произношение коварных звуков и раз и навсегда снимем путаницу между похожими словами.","video_url":"https://vk.com/video-230370533_456239045","vk_attachment":"video-230370533_456239045","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  21,
  2,
  'theory',
  '{"text":"✨ УРОК 21. УКАЗАТЕЛЬНЫЕ СЛОВА\n\nДавай разделим наше пространство на две зоны: БЛИЗКО (то, что можно потрогать рукой) и ДАЛЕКО (то, на что нужно показать пальцем или посмотреть вдаль).\n\nЕСЛИ ПРЕДМЕТ ОДИН (Единственное число + глагол IS):\n\n• THIS [зис] - Этот / Эта / Это (находится БЛИЗКО)\nПример: This is a book. [зис из а бук] - Это книга (она прямо у меня в руках).\n\n• THAT [зэт] - Тот / Та / То (находится ДАЛЕКО)\nПример: That is a server. [зэт из а сё́уэр] - То сервер (он стоит вон там, на другом конце комнаты).\n\nЕСЛИ ПРЕДМЕТОВ МНОГО (Множественное число + глагол ARE):\n\n• THESE [зииз] - Эти (находятся БЛИЗКО)\nПример: These are apples. [зииз ар эплз] - Это яблоки (они лежат на столе прямо передо мной).\n\n• THOSE [зоуз] - Те (находятся ДАЛЕКО)\nПример: Those are monitors. [зоуз ар мо́ниторз] - То мониторы (вон те, у противоположной стены офиса).\n\n⚠️ ФОНЕТИЧЕСКАЯ ЛОВУШКА:\nСлова This (этот) и These (эти) звучат очень похоже! \nThis - произносится коротко, сжато, с обрывистым звуком [зис].\nThese - произносится долго, с улыбкой, растягивая гласную [зиииз]. Прислушайся к этому в видео Лекси!","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  21,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: НАВЕДЕНИЕ ПОРЯДКА В ОФИСЕ\n\nДавай послушаем, как тестировщик Макс и дизайнер Анна разбирают гаджеты и коробки на рабочем пространстве перед презентацией:\n\nMax: Anna, look at this laptop here. Is it your laptop?\nAnna: Yes, it is! Thank you. And what is that device over there, near the window?\nMax: That is our new router. It is very fast. \nAnna: Great! And what about these papers on my desk? \nMax: Oh, those are important documents. And please look at those boxes near the door. They are for our developers.\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nМакс: Анна, посмотри на этот ноутбук здесь. Это твой ноутбук? (laptop близко - this)\nАнна: Да, мой! Спасибо. А что это за устройство вон там, у окна? (router далеко - that)\nМакс: То наш новый роутер. Он очень быстрый.\nАнна: Отлично! А как насчет этих бумаг на моем столе? (papers близко - these)\nМакс: О, то важные документы. И, пожалуйста, посмотри на те коробки у двери. Они для наших разработчиков. (boxes далеко - those)\n\n💡 СУПЕР-ЛАЙФХАК ДЛЯ ТЕЛЕФОНА И ПРЕЗЕНТАЦИЙ:\nКогда ты звонишь кому-то по телефону или заходишь на онлайн-созвон, нельзя говорить \"I am Aleksey\". Принято представляться именно через слово This!\nНосители говорят: \"Hello, this is Aleksey\" [хэлóу, зис из Алексэй] (дословно: Привет, это есть Алексей). Запомни этот маркер профессионального общения!\n\n🔥 Твое мини-задание: Возьми любой предмет в руку (например, ручку или чашку) и скажи вслух: \"This is a pen\" или \"This is a cup\". Затем покажи пальцем на любой предмет вдали и скажи: \"That is...\". Прокачай расстояние!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


