INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  22,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-УРОК ОТ LEXI: МИР ВОКРУГ ТЕБЯ\n\nПривет! На связи Lexi. Представьте, что вам нужно описать свой рабочий кабинет, квартиру для аренды или рассказать иностранному коллеге, что в вашем офисе есть кофемашина и два удобных кресла.\n\nВ русском языке мы говорим обычным путем: \"На столе стоит ноутбук\" или \"В комнате есть два стула\". Мы начинаем с места. В английском языке для этого существует специальная и очень популярная конструкция, которая буквально переворачивает логику предложения с ног на голову.\n\nВключайте короткое видео! Я научу вас смотреть на пространство глазами англичанина и покажу, как легко описывать любые локации без долгих раздумий над структурой.","video_url":"https://vk.com/video-230370533_456239046","vk_attachment":"video-230370533_456239046","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  22,
  2,
  'theory',
  '{"text":"✨ УРОК 22. КОНСТРУКЦИЯ THERE IS / THERE ARE\n\nСама по себе фраза \"There is\" или \"There are\" переводится как \"там есть\" или \"существует\". Мы используем ее всегда, когда хотим заявить: в таком-то месте находится такой-то предмет.\n\nВЫБОР ЗАВИСИТ ТОЛЬКО ОТ КОЛИЧЕСТВА ПРЕДМЕТОВ:\n\n1. Если предмет ОДИН (Единственное число):\n• THERE IS... [зэар из]\nПример: There is a table in the room. [зэар из а тэйбл ин зэ рум] - В комнате есть стол.\n\n2. Если предметов ДВА И БОЛЕЕ (Множественное число):\n• THERE ARE... [зэар ар]\nПример: There are two chairs near the table. [зэар ар ту чэарз ни́ар зэ тэйбл] - Возле стола стоят два стула.\n\n⚠️ ЗОЛОТОЕ ПРАВИЛО ПЕРЕВОДА НА РУССКИЙ:\nЗапомни классный секрет: английское предложение начинается с конструкции \"There is/are\", а вот переводить его на русский язык правильнее и красивее всего с самого КОНЦА - то есть с места действия!\n• Англичане говорят: Есть стол в комнате.\n• Мы переводим: В комнате есть стол.","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  22,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: ПРОВЕРКА НОВОГО ОФИСА\n\nДавай послушаем, как проджект-менеджер Сэм и дизайнер София осматривают свой новый кабинет в ИТ-технопарке:\n\nSam: Sofia, welcome to our new room! What do you think?\nSofia: Wow, it is great! There is a big window and there is a modern whiteboard on the wall.\nSam: Yes! And look at the workplaces. There is a clean desk for you.\nSofia: Perfect! But where are the seats?\nSam: Don''t worry. There are two comfortable chairs near the window. And there are three monitors in those boxes!\nSofia: Awesome! I love this place.\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nСэм: София, добро пожаловать в наш новый кабинет! Что думаешь?\nСофия: Вау, он отличный! В комнате есть большое окно, а на стене висит современная маркерная доска. (в оригинале - There is a window, there is a whiteboard)\nСэм: Да! И посмотри на рабочие места. Для тебя тут есть чистый стол. (There is a clean desk)\nСофия: Прекрасно! Но где сиденья?\nСэм: Не переживай. У окна стоят два удобных стула. А в тех коробках лежат три монитора! (There are two chairs, there are three monitors)\nСофия: Круто! Мне нравится это место.\n\n💡 РАЗГОВОРНЫЙ СУПЕР-ЛАЙФХАК:\nВ реальной жизни никто не говорит длинное \"There is\". Носители сокращают его до короткого слова There''s [зэарз].\nПример: There''s a laptop on my desk. (На моем столе стоит ноутбук).\n\nА что делать, если ты перечисляешь разные предметы? Например: \"На столе стоит один ноутбук и две чашки\". Что выбрать: is или are? \nЗапомни правило первого соседа! Мы выбираем форму по самому первому предмету в списке. Ноутбук один? Значит говорим: There is a laptop and two cups.\n\n🔥 Твое мини-задание: Посмотри на свой рабочий стол прямо сейчас. Найди один главный предмет и назови его вслух по нашей формуле. Например: \"There is a phone on my desk\". Почувствуй логику языка!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


