VALUES (
  23,
  1,
  'theory',
  '{"text":"🎬 СЛОВАРНЫЙ РОК ОТ LEXI: ОКРУЖАЮЩИЙ МИР\n\nПривет! На связи Lexi. Вы уже умеете строить сложные конструкции, говорить, что и где находится, указывать на предметы вдали и вблизи. Настало время мощно расширить ваш словарный запас!\n\nСегодня мы изучим 6 главных слов, из которых состоит любое рабочее пространство, офис или жилая комната. Телефон, компьютер, стол, стул - это то, с чем вы взаимодействуете каждую секунду.\n\nВключайте короткое видео! Мы разберем правильное произношение этих существительных, чтобы вы не путали похожие звуки, и сразу научимся соединять их с уже изученной грамматикой.","video_url":"https://vk.com/video-230370533_456239047","vk_attachment":"video-230370533_456239047","button_text":"К теории ➡️"}'
)
