INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  24,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-УРОК ОТ LEXI: РАСКРАШИВАЕМ РЕЧЬ\n\nПривет! На связи Lexi. До этого момента мы учили в основном «голые» предметы - телефон, компьютер, комната. Но ведь в жизни все они имеют свои особенности: телефон может быть новым, компьютер - быстрым, а комната - большой и красивой!\n\nСегодня мы пройдем базовые прилагательные и цвета. Это те самые слова-краски, которые сделают твой английский по-настоящему живым, детальным и интересным для собеседника.\n\nВключайте короткое видео! Мы разберем правильное произношение, избавимся от типичных ошибок и узнаем один секретный лайфхак, благодаря которому английские прилагательные окажутся в 10 раз проще русских!","video_url":"https://vk.com/video-230370533_456239049","vk_attachment":"video-230370533_456239049","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  24,
  2,
  'theory',
  '{"text":"✨ УРОК 24. ЦВЕТА И ПРИЛАГАТЕЛЬНЫЕ\n\nДавай сразу раскроем главный секрет английского языка: прилагательные здесь НИКОГДА не меняют свои окончания! \n\nВ русском языке мы мучаемся: большОЙ стол, большАЯ комната, большОЕ окно, большИЕ сумки. Четыре разных окончания! В английском языке во всех этих случаях будет одно неизменное слово - BIG.\n\nТВОЙ НАБОР СЛОВ-КРАСОК:\n\n• Big [биг] - большой / большая / большое\n• Small [смол] - маленький / маленькая\n• Good [гуд] - хороший\n• Bad [бэд] - плохой\n• New [нью] - новый\n• Old [оулд] - старый\n• Beautiful [бью́тифл] - красивый / прекрасная\n\nБАЗОВЫЕ ЦВЕТА:\n• Red [рэд] - красный\n• Blue [блу] - синий / голубой\n• Green [грин] - зеленый\n• Black [блэк] - черный\n• White [уайт] - белый\n\n⚠️ ПРАВИЛО ПОРЯДКА СЛОВ:\nПрилагательное всегда ставится строго ПЕРЕД существительным, которое оно описывает!\n• Правильно: a big room (большая комната)\n• Неправильно: a room big","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  24,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ:ОБСУЖДАЕМ ПОКУПКИ\n\nДавай послушаем, как два дизайнера, Анна и Макс, обсуждают новые гаджеты и рабочее пространство в своей ИТ-студии:\n\nAnna: Max, look at my new phone! It is blue.\nMax: Wow, it is beautiful! But it is very small. Do you like it?\nAnna: Yes, I do. It is a good phone. And look at that old computer on your table. It is bad!\nMax: Yes, it is very old. But there is a new big monitor in that white box. It is for our team!\nAnna: Awesome! That is a green light for our new project!\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nАнна: Макс, посмотри на мой новый телефон! Он синий. (в оригинале - new phone, blue)\nМакс: Вау, он красивый! Но он очень маленький. Тебе он нравится? (beautiful, small)\nАнна: Да. Это хороший телефон. И посмотри на тот старый компьютер на твоем столе. Он плохой! (good phone, old computer, bad)\nМакс: Да, он очень старый. Но в той белой коробке лежит новый большой монитор. Он для нашей команды! (white box, new big monitor)\nАнна: Круто! Это зеленый свет для нашего нового проекта!\n\n💡 ИНТЕРЕСНЫЙ ЛАЙФХАК:\nЕсли перед существительным стоит и цвет, и размер, то на первое место англичане всегда ставят размер, а уже ближе к предмету - цвет. \nПравильно говорить: a big blue bag (большая синяя сумка), но не a blue big bag.\n\n🔥 Твое мини-задание: Опиши свой любимый гаджет двумя словами. Например: \"new phone\" или \"big computer\". Скажи это вслух прямо сейчас!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


