INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  25,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-УРОК ОТ LEXI: СИНТЕЗ ОПИСАНИЙ\n\nПривет! На связи Lexi. Мы уже отлично знаем названия базовых предметов, выучили цвета, размеры и простые оценки качества. Сегодня финальный аккорд этого блока - мы научимся полноценно описывать вещи вокруг нас.\n\nВы разберетесь, как строить предложения двух типов: короткие вроде \"It is small\" и более детальные вроде \"This phone is new\". Это закроет все вопросы о том, как презентовать свои гаджеты, рабочее место или продукты.\n\nВключай короткое видео! Мы разберем, как правильно сочетать указательные слова и прилагательные, чтобы твоя речь лилась естественно и без ошибок.","video_url":"https://vk.com/video-230370533_456239050","vk_attachment":"video-230370533_456239050","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  25,
  2,
  'theory',
  '{"text":"✨ УРОК 25. ОПИСАНИЕ ПРЕДМЕТОВ\n\nКогда нам нужно описать предмет, у нас есть два главных пути. Выбор зависит от того, назвали мы сам предмет прямо сейчас в предложении или нет.\n\nСПОСОБ 1. Краткое описание (Через местоимение IT)\nЕсли собеседник уже понимает по контексту, о какой вещи идет речь, не нужно постоянно повторять ее название. Мы просто заменяем предмет словом It (Оно / Это).\nФОРМУЛА: It is + прилагательное\n• It is small [ит из смол] - Оно маленькое.\n• It is new [ит из нью] - Оно новое.\n\nСПОСОБ 2. Точечное описание (Через указательные слова)\nЕсли мы хотим четко указать на конкретную вещь руками или взглядом и описать именно ее, мы называем саму вещь сразу после слов This (этот) или That (тот).\nФОРМУЛА: This / That + предмет + is + прилагательное\n• This phone is new [зис фоун из нью] - Этот телефон новый.\n• That computer is old [зэт кэмпью́тэр из оулд] - Тот компьютер старый.\n\n🔎 Обрати внимание на разницу:\n\"This is a new phone\" переводится как \"Это новый телефон\". \n\"This phone is new\" переводится как \"Этот телефон новый\". \nОба варианта абсолютно верны, но второй делает сильный акцент именно на качестве и состоянии вещи!","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  25,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: ПРОВЕРКА ГАДЖЕТОВ\n\nДавай послушаем, как два специалиста, Алекс и Джесс, обсуждают новые устройства на рабочем пространстве в своей студии:\n\nAlex: Jess, look at this smartphone. What do you think?\nJess: Wow! This phone is new. It is beautiful.\nAlex: Yes, but it is small. Look at that screen over there. That monitor is old.\nJess: You are right, it is bad. But these new mice on the table are great!\nAlex: Yes, they are perfect for our work.\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nАлекс: Джесс, посмотри на этот смартфон. Что думаешь?\nДжесс: Вау! Этот телефон новый. Он красивый.\nАлекс: Да, но он маленький. Посмотри на тот экран вон там. Тот монитор старый.\nДжесс: Ты права, он плохой. Но эти новые мышки на столе отличные!\nАлекс: Да, они идеальны для нашей работы.\n\n💡 ГРАММАТИЧЕСКИЙ ЛАЙФХАК ДЛЯ МНОЖЕСТВЕННОГО ЧИСЛА:\nЕсли предметов много, не забывай менять не только указательное слово (These / Those), но и форму нашего глагола-помощника на ARE!\n• Единственное число: This phone is new.\n• Множественное число: These phones are new. (Эти телефоны новые).\n\n🔥 Твое мини-задание: Посмотри на свой главный рабочий инструмент прямо сейчас и скажи вслух фразу по нашей второй формуле. Например: \"This computer is good\" или \"This phone is beautiful\". Начни говорить на автомате!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


