  content_json
)
VALUES (
  26,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-МЕНЮ ОТ LEXI: ГОВОРИМ О ВКУСАХ\n\nПривет! На связи Lexi. Сегодня у нас невероятно вкусная и практичная тема - Еда и напитки (Food and Drinks). \n\nЗаказать утренний кофе в Лондоне, купить свежий хлеб в супермаркете или рассказать иностранному коллеге о своем любимом блюде на обед - для всего этого нужны базовые продукты.\n\nВключайте наше короткое видео! Мы разберем правильное произношение, избавимся от жесткого акцента и разберем главный секрет: почему англичане никогда не считают рис и воду поштучно и как это влияет на грамматику.","video_url":"https://vk.com/video-230370533_456239051","vk_attachment":"video-230370533_456239051","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  26,
  2,
  'theory',
  '{"text":"✨ УРОК 26. ЕДА И НАПИТКИ\n\nДавай добавим в твой арсенал 7 главных продуктов и напитков, которые мы используем каждый день.\n\nНАПИТКИ:\n• Water [уо́тэр] - вода\n• Tea [ти] - чай\n• Coffee [ко́фи] - кофе\n\nЕДА:\n• Bread [брэд] - хлеб\n• Apple [эпл] - яблоко\n• Rice [раис] - рис\n• Chicken [чи́кин] - курица / цыпленок\n\n⚠️ ГЛАВНЫЙ СЕКРЕТ: МАТЕМАТИКА НА ТАРЕЛКЕ\nВ английском языке еда делится на исчисляемую (можно посчитать пальцами) и неисчисляемую (нельзя посчитать поштучно, только ложками, стаканами или килограммами).\n\n• Исчисляемые (например, Apple): Перед ними можно ставить артикль AN или говорить во множественном числе: an apple (одно яблоко), two apples (два яблока).\n\n• Неисчисляемые (например, Water, Rice, Bread, Coffee): Их нельзя посчитать поштучно! Нельзя сказать \"один рис\" или \"три воды\". Перед ними никогда не ставится артикль \"a/an\" и к ним нельзя добавить окончание -s. Мы говорим просто: I drink water, I eat rice.","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  26,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: ОБЕД В ИТ-ОФИСЕ\n\nДавай послушаем, как менеджер Сэм и разработчик Алексей обсуждают свое меню во время обеденного перерыва в корпоративной столовой:\n\nSam: Alex, hello! What is your lunch today?\nAlex: Hi Sam! There is chicken and rice on my plate. \nSam: Oh, it looks good! I have a green apple and some white bread. \nAlex: Nice. Do you want some hot tea?\nSam: No, thanks. I usually drink black coffee or pure water. \nAlex: Good choice. Have a nice lunch!\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nСэм: Алекс, привет! Какой у тебя сегодня обед?\nАлексей: Привет, Сэм! У меня на тарелке курица и рис. (в оригинале без артиклей - chicken and rice)\nСэм: О, выглядит хорошо! У меня зеленое яблоко и немного белого хлеба. (an apple - посчитать можно, bread - нельзя)\nАлексей: Приятно. Хочешь горячего чаю?\nСэм: Нет, спасибо. Я обычно пью черный кофе или чистую воду.\nАлексей: Хороший выбор. Приятного обеда!\n\n💡 ОПАСНАЯ ЛОВУШКА СО СЛОВОМ CHICKEN:\nЗапомни забавный культурный нюанс. Если ты говоришь про еду, слово chicken - неисчисляемое. Фраза \"I eat chicken\" переводится как \"Я ем курятину (мясо)\". \nНо если ты случайно добавишь артикль \"a\" и скажешь \"I eat a chicken\", это будет переводиться как \"Я ем целую живую курицу (птицу) живьем вместе с перьями\". Будь аккуратен с артиклями!\n\n🔥 Твое мини-задание: Назови вслух свой любимый утренний напиток по нашей формуле. Например: \"I drink coffee every morning\" или \"I drink water\". Скажи это прямо сейчас!","button_text":"Перейти к тестов ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


