INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  27,
  1,
  'theory',
  '{"text":"🎬 ВИДЕО-НАСТРОЙКА ОТ LEXI: ГОВОРИМ О ПРЕДПОЧТЕНИЯХ\n\nПривет! На связи Lexi. Сегодня мы пройдем одну из самых эмоциональных и приятных тем - как рассказать о том, что мы любим, и о том, что терпеть не можем.\n\nВкусы у всех разные, особенно когда речь заходит о еде, напитках или рабочих задачах. Умение четко сказать \"Мне это нравится\" или \"Я это не люблю\" - это основа любого живого общения и первый шаг к тому, чтобы показать свой характер собеседнику.\n\nВключайте наше короткое видео! Мы разберем правильное произношение, избавимся от типичных ошибок с предлогами и научимся звучать легко и непринужденно.","video_url":"https://vk.com/video-230370533_456239052","vk_attachment":"video-230370533_456239052","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  27,
  2,
  'theory',
  '{"text":"✨ УРОК 27. ТЕМА: I LIKE / I DON''T LIKE\n\nВ английском языке выразить свою симпатию к предмету или продукту очень просто. Нам не нужно менять падежи или окончания, как в русском!\n\nДАВАЙ РАЗБЕРЕМ ДВЕ ПРОСТЫЕ ФОРМУЛЫ:\n\n1. Если тебе что-то нравится:\nФОРМУЛА: I like [ай лайк] + предмет\nПример: I like coffee. [ай лайк ко́фи] - Мне нравится кофе (дословно: Я люблю кофе).\n\n2. Если тебе что-то НЕ нравится:\nЗдесь мы зовем нашего старого знакомого - отрицательного помощника don''t!\nФОРМУЛА: I don''t like [ай доунт лайк] + предмет\nПример: I don''t like fish. [ай доунт лайк фиш] - Мне не нравится рыба.\n\n⚠️ ГЛАВНАЯ ОШИБКА РУССКИХ (ЛИШНИЙ ПРЕДЛОГ TO):\nВ русском языке мы говорим: \"Мне нравится...\". Из-за этого новички пытаются перевести слово \"мне\" как \"to me\" и говорят: \"To me like coffee\". Это огромная ошибка! \nАнгличане мыслят прямо: Я люблю кофе. Поэтому говорим строго: I like coffee. Никаких предлогов \"to\" перед словом like ставить не нужно!","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  27,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: ОБСУЖДЕНИЕ МЕНЮ В КАФЕ\n\nДавай послушаем, как менеджер Сэм и аналитик Кейт выбирают еду и напитки во время обеденного перерыва:\n\nSam: Kate, do you like this cafe? \nKate: Yes, I do. I like their green tea. \nSam: Oh, I don''t like tea. I always drink black coffee. What about lunch? \nKate: Well, I like chicken, but I don''t like fish. \nSam: Really? I like fish! Their fish and rice are perfect. \nKate: Good! Everyone has different tastes!\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nСэм: Кейт, тебе нравится это кафе?\nКейт: Да! Мне нравится их зеленый чай. (в оригинале - I like their green tea)\nСэм: О, я не люблю чай. Я всегда пью черный кофе. Как на счет обеда? (I don''t like tea)\nКейт: Ну, мне нравится курица, но я не люблю рыбу. (I like chicken, I don''t like fish)\nСэм: Правда? А я люблю рыбу! Их рыба с рисом идеальны.\nКейт: Хорошо! У каждого свои вкусы!\n\n💡 СУПЕР-ЛАЙФХАК ДЛЯ УСИЛЕНИЯ СМЫСЛА:\nЕсли тебе что-то нравится безумно сильно, вместо обычного \"like\" используй яркое слово LOVE [лав] (обожаю / люблю).\nПример: I love English! (Я обожаю английский!).\nА если что-то вызывает сильный негатив, вместо \"don''t like\" можно смело сказать HATE [хэйт] (ненавижу).\nПример: I hate bad code. (Я ненавижу плохой код).\n\n🔥 Твое мини-задание: Назови один продукт, который ты обожаешь, и один, который не любишь, используя наши формулы. Скажи это вслух прямо сейчас!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


