  1,
  'theory',
  '{"text":"🎬 ВИДЕО-ИНСТРУКТАЖ ОТ LEXI: ТВОИ СУПЕРСИЛЫ\n\nПривет! На связи Lexi. Сегодня мы пройдем один из самых любимых глаголов всех студентов во всем мире. Это глагол CAN (могу, умею). \n\nС его помощью вы сможешь рассказать работодателю, какими технологиями вы владеете, заявить на созвоне, что можете решить сложную задачу, или просто обсудить свои хобби за пределами офиса.\n\nВключайте короткое видео! Я расскажу, почему этот глагол называют настоящим супергероем грамматики, как он облегчает нам жизнь и почему с ним невозможно запутаться в окончаниях.","video_url":"https://vk.com/video-230370533_456239053","vk_attachment":"video-230370533_456239053","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  28,
  2,
  'theory',
  '{"text":"✨ УРОК 28. ГЛАГОЛ CAN И CAN''T\n\nГлагол CAN [кэн] переводится как \"мочь\" или \"уметь\". Это модальный глагол, а значит, у него есть уникальные суперсвойства, за которые мы его обожаем.\n\nСУПЕРСВОЙСТВА ГЛАГОЛА CAN:\n1. Он никогда НЕ меняет свою форму. Ему плевать на правила He/She/It! Никаких окончаний -s добавлять не нужно. Всегда пишется просто CAN.\n2. После него никогда НЕ ставится частица \"to\".\n3. Ему НЕ нужны глаголы-помощники (do/does) для вопросов и отрицаний. Он все делает сам!\n\nФОРМУЛА УТВЕРЖДЕНИЯ: Кто + CAN + чистый глагол действия\n• I can speak English. [ай кэн спик и́нглиш] - Я умею говорить по-английски.\n• He can code. [хи кэн коуд] - Он умеет программировать.\n\nФОРМУЛА ОТРИЦАНИЯ: Кто + CAN''T + чистый глагол действия\nВ отрицании мы просто добавляем к нему частицу not. Сокращенно это пишется как CAN''T [кэнт] (в американском английском) или [кант] (в британском).\n• I can''t swim. [ай кэнт уим] - Я не умею плавать.\n• She can''t come. [ши кэнт кам] - Она не может прийти.","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  28,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: РАСПРЕДЕЛЕНИЕ ЗАДАЧ\n\nДавай послушаем разговор проджект-менеджера Макса и разработчика Сэма на утреннем планировании задач (дейли-митинге):\n\nMax: Sam, hello! Can you look at this bug?\nSam: Hi Max! Yes, I can. I can fix this code easily.\nMax: Awesome. Can you speak with the client about it later?\nSam: Oh, no, I can''t. I can read English documents, but I can''t speak fluently. \nMax: No problem! Our team lead can do that. He can speak English perfectly.\nSam: Great! Then I can focus on my tasks.\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nМакс: Сэм, привет! Ты можешь посмотреть этот баг? (в оригинале - Can you look)\nСэм: Привет, Макс! Да, могу. Я могу легко исправить этот код. (I can fix)\nМакс: Потрясающе. Ты можешь поговорить об этом с клиентом позже? (Can you speak)\nСэм: О, нет, не могу. Я умею читать английские документы, но не умею говорить бегло. (I can read, I can''t speak)\nМакс: Без проблем! Наш тимлид может сделать это. Он идеально говорит по-английски. (He can do, He can speak)\nСэм: Отлично! Тогда я могу сосредоточиться на своих задачах. (I can focus)\n\n💡 ФОНЕТИЧЕСКИЙ ЛАЙФХАК: КАК ИХ РАЗЛИЧАТЬ НА СЛУХ?\nВ живой и быстрой речи иностранцев утвердительное слово \"can\" звучит очень коротко, блекло и смазанно, почти как [кн] (I кн speak English). Ударение на него не падает.\nА вот отрицание \"can''t\" они всегда выделяют голосом, произносят громко, отчетливо и тянут гласную: [кэээнт] или [кааант]. Так что если ты слышишь яркое, сильное слово - это точно отрицание!\n\n🔥 Твое мини-задание: Скажи вслух, какой профессиональный или личный навык у тебя есть, используя формулу \"I can...\". Например: \"I can code\" или \"I can speak English\". Похвали себя вслух!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


