VALUES (
  28,
  5,
  'quiz_choice',
  '{"question":"Как правильно переводится на русский язык предложение нового иностранного знакомого: «I can''t swim, but I can play tennis»?","options":[{"id":"a","text":"Я умею плавать, но не умею играть в теннис.","is_correct":false},{"id":"b","text":"Я не умею плавать, но умею играть в теннис.","is_correct":true},{"id":"c","text":"Я не могу плавать и не люблю играть в теннис.","is_correct":false}],"explanation_if_wrong":"Правильный ответ - «Я не умею плавать, но умею играть в теннис.». Слово «can''t» означает отрицание (не умею / не могу), а слово «can» означает утверждение (умею)."}'
