INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  29,
  1,
  'theory',
  '{"text":"🎬 ПРАКТИКА С LEXI: ЗАКАЗЫВАЕМ КОФЕ И ПОКУПАЕМ СУВЕНИРЫ\n\nПривет! На связи Lexi. Мы уже знаем названия еды, напитков и предметов. Сегодня мы применим эти знания в реальной жизни: отправимся в виртуальное кафе и магазин!\n\nКак вежливо попросить чашку капучино? Как узнать цену вон того крутого худи? В русском мы часто говорим «мне пожалуйста кофе» или «сколько стоит?». В английском для этого есть три волшебные фразы, которые мгновенно превратят тебя в вежливого и приятного покупателя в любой стране мира.\n\nВключайте наше короткое видео! Мы разберем, как делать заказы легко, уверенно и без языкового барьера.","video_url":"https://vk.com/video-230370533_456239054","vk_attachment":"video-230370533_456239054","button_text":"К теории ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  29,
  2,
  'theory',
  '{"text":"✨ УРОК 29. ТРИ КИТА ДЛЯ КАФЕ И МАГАЗИНА\n\nДавай разберем три главные фразы, с помощью которых можно купить абсолютно все: от чашки эспрессо до нового ноутбука.\n\n1. Вежливая просьба: I would like... [ай ууд лайк] (Я бы хотел... / Я бы хотела...). Это самый универсальный и культурный способ заказать что-то.\nПример: I would like a coffee, please. (Я бы хотел кофе, пожалуйста).\n\n2. Разговорный заказ: Can I have...? [кэн ай хэв] (Можно мне...? / Могу я получить...?). Носители языка обожают эту фразу. Она звучит очень естественно и дружелюбно.\nПример: Can I have a tea, please? (Можно мне чай, пожалуйста?).\n\n3. Вопрос о цене: How much is it? [хау мач из ит] (Сколько это стоит?). Если предметов много, мы меняем «is it» на «are they»: How much are they? (Сколько они стоят?).\nПример: How much is this bag? (Сколько стоит эта сумка?).","button_text":"Понятно, дальше ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  29,
  3,
  'theory',
  '{"text":"📖 ЖИВОЙ МИКРО-ДИАЛОГ: В ЛОНДОНСКОМ КОФЕ-ШОПЕ\n\nДавай послушаем, как наш специалист Алекс делает заказ в кафе, а затем покупает сувенир в магазине:\n\nАлекс заходит в кафе:\nBarista: Hello! What would you like?\nAlex: Hi! Can I have a black coffee and a fresh bread, please?\nBarista: Sure! Anything else?\nAlex: No, thanks. How much is it?\nBarista: It is 5 pounds, please.\n\nАлекс подходит к стойке с сувенирами:\nAlex: Excuse me, I would like this blue cup. How much is it?\nSeller: This cup is 10 pounds.\nAlex: Great, thank you!\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nБариста: Привет! Что бы вы хотели?\nАлекс: Привет! Можно мне черный кофе и свежий хлеб, пожалуйста?\nБариста: Конечно! Что-нибудь еще?\nАлекс: Нет, спасибо. Сколько это стоит?\nБариста: С вас 5 фунтов.\n\nАлекс: Простите, я бы хотел эту синюю кружку. Сколько она стоит?\nПродавец: Эта кружка стоит 10 фунтов.\nАлекс: Отлично, спасибо!\n\n💡 РАЗГОВОРНЫЙ ЛАЙФХАК:\nВ реальной жизни ты можешь сокращать фразу I would like до формы I''d like [айд лайк]. Это звучит супер-естественно. Вместо «I would like a coffee» смело говори «I''d like a coffee».\n\n🔥 Твое мини-задание: Представь, что ты заказываешь свой любимый напиток прямо сейчас. Скажи вслух с выражением: «Can I have a coffee, please?». Почувствуй себя уверенно!","button_text":"Перейти к тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


