INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  30,
  1,
  'theory',
  '{"text":"🎬 ФИНАЛЬНЫЙ АККОРД С LEXI: ТЫ СДЕЛАЛ ЭТО!\n\nПривет! На связи Lexi. Я невероятно горжусь вами! Вы прошли огромный, серьезный путь от самого нуля, букв и первых связок до полноценного понимания базовой грамматики. \n\nСегодня у нас триумфальный урок - большое финальное повторение уровня А1. Мы не будем учить новые правила. Вместо этого мы возьмем все ваши суперсилы (рассказ о себе, работу, семью, распорядок дня, еду и коварные вопросы) и соберем их в один монолитный, красивый фундамент.\n\nВключайте итоговое видео! Мы прокрутим назад всю пленку наших занятий, подсветим главные фишки носителей языка и отпразднуем ваш первый масштабный шаг в английском.","video_url":"https://vk.com/video-230370533_456239055","vk_attachment":"video-230370533_456239055","button_text":"К главному резюме ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  30,
  2,
  'theory',
  '{"text":"✨ УРОК 30. КАРТА ТВОИХ ЗНАНИЙ (ВСПОМНИТЬ ВСЁ)\n\nДавай посмотрим на систему, которую ты построил в своей голове. Теперь у тебя есть четкие математические формулы для пяти главных жизненных тем:\n\n1. Рассказ о себе и глагол To Be:\nТы умеешь называть имя, профессию, локацию и описывать состояние без лишних зависаний.\nФормула: I am a programmer. I''m not tired.\n\n2. Семья и люди вокруг:\nТы можешь легко описать близких, коллег или партнеров, используя He, She, They и помня про железное окончание -s для третьего лица.\nФормула: My partner manages the team. She lives in Moscow.\n\n3. Расписание и рутина (Present Simple):\nГлаголы wake up, work, eat, sleep работают на тебя в связке со словами-маркерами и четким порядком слов.\nФормула: In the morning I usually wake up early, then I work.\n\n4. Еда, вкусы и вежливые заказы:\nТы разделяешь продукты на исчисляемые и неисчисляемые, умеешь хвалить, ругать и просить счет.\nФормула: I like coffee, but I don''t like fish. Can I have an apple, please?\n\n5. Вопросы и короткие эхо-ответы:\nТы знаешь, как сильные глаголы (am/is/are/can) сами прыгают вперед, и как слабым действиям помогают Do и Does.\nФормула: Do you study English? - Yes, I do! Is he ready? - No, he isn''t.","button_text":"Посмотреть живой пример ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


INSERT INTO lesson_steps (
  lesson_id,
  order_num,
  step_type,
  content_json
)
VALUES (
  30,
  3,
  'theory',
  '{"text":"📖 МАСТЕР-ДИАЛОГ: ВСТРЕЧА НА МЕЖДУНАРОДНОЙ ВСТРЕЧЕ\n\nПосмотри, как абсолютно все темы нашего курса сплетаются в один живой, взрослый и естественный разговор двух специалистов в лаунж-зоне крупного ИТ-хаба:\n\nTom: Hello! Can I sit here? Is this chair free?\nAlex: Hi! Yes, it is. Please, sit down.\nTom: Thanks! This is a great place. Are you a developer?\nAlex: Yes, I am. I have an IT agency and an AI school. My name is Alex. And you?\nTom: Awesome! I''m Tom, a project manager. Where do you live, Alex?\nAlex: I live in Solnechnogorsk and often travel to Moscow. My wife Marina and I work together. She manages our development team.\nTom: Wow, that''s beautiful! Do you work every day?\nAlex: Usually, yes. I wake up early, drink black coffee and code. I don''t like tea. Can I have that green apple from the table?\nTom: Sure, here you go! Can you speak English fluently?\nAlex: I can speak well, but I always study every evening to be better!\nTom: Perfect! You sound like a real pro.\n\n🇷🇺 ПЕРЕВОД ДЛЯ ПРОВЕРКИ:\n\nТом: Привет! Можно мне сесть здесь? Этот стул свободен?\nАлекс: Привет! Да, свободен. Пожалуйста, присаживайся.\nТом: Спасибо! Это отличное место. Ты разработчик?\nАлекс: Да. У меня есть ИТ-агентство и школа искусственного интеллекта. Меня зовут Алекс. А тебя?\nТом: Потрясающе! Я Том, проджект-менеджер. Где ты живешь, Алекс?\nАлекс: Я живу в Солнечногорске и часто езжу в Москву. Мы с женой Мариной работаем вместе. Она руководит нашей командой разработки.\nТом: Вау, это прекрасно! Ты работаешь каждый день?\nАлекс: Обычно да. Я просыпаюсь рано, пью черный кофе и пишу код. Я не люблю чай. Можно мне вон то зеленое яблоко со стола?\nТом: Конечно, держи! Ты бегло говоришь по-английски?\nАлекс: Я могу говорить хорошо, но всегда учусь каждый вечер, чтобы стать лучше!\nТом: Идеально! Ты звучишь как настоящий профи.\n\n💡 ФИНАЛЬНЫЙ НАПУТСТВЕННЫЙ ЛАЙФХАК:\nТы заметил? Весь этот большой, солидный диалог построен ИСКЛЮЧИТЕЛЬНО на правилах первых 30 уроков. Никакой магии, никаких сверхсложных времен. Главный секрет разговорного английского - до автоматизма отточить базовые кирпичики. Если они стоят ровно, твоя речь уже понятна миру на 100%!\n\n🔥 Твое финальное мини-задание: Скажи вслух самую главную фразу этого курса: \"I can speak English!\". Сделай это громко и уверенно!","button_text":"Перейти к финальным тестам ➡️"}'
)
ON CONFLICT(lesson_id, order_num) DO UPDATE SET
  step_type = excluded.step_type,
  content_json = excluded.content_json;


